function gcd(a, b) { while (b) { [a, b] = [b, a % b]; } return a; }
var gcdSum = function(nums) {
    let mx = 0;
    const prefixGcd = [];
    for (const v of nums) {
        mx = Math.max(mx, v);
        prefixGcd.push(gcd(v, mx));
    }
    prefixGcd.sort((a, b) => a - b);
    let total = 0;
    let i = 0, j = prefixGcd.length - 1;
    while (i < j) {
        total += gcd(prefixGcd[i], prefixGcd[j]);
        i++;
        j--;
    }
    return total;
};
